{
    "level": "B1–B2",
    "intro": "In this topic, you will learn about <strong>no, none, neither, either</strong>, when to use them and what is the difference between them. difference.",
    "rules": [
        {
            "label": "No",
            "color": "rose",
            "text": "<strong>No</strong> - none (before a noun):",
            "example": "No students came. / I have no money."
        },
        {
            "label": "None",
            "color": "purple",
            "text": "<strong>None</strong> — none (independently):",
            "example": "None of the students came. / I have none."
        },
        {
            "label": "Neither/Either",
            "color": "blue",
            "text": "<strong>Neither/Either</strong> — none/any (of two):",
            "example": "Neither option works. / Either way is fine."
        }
    ]
}

{
    "title": "1. Overview No / None / Neither / Either",
    "intro": "These words express absence or choice:",
    "items": [
        {
            "label": "No",
            "title": "No (marker)",
            "subtitle": "Used before a noun: no money, no time"
        },
        {
            "label": "None",
            "title": "None (pronoun)",
            "subtitle": "Used independently: none of them, I have none"
        },
        {
            "label": "Neither/Either",
            "title": "Of two options",
            "subtitle": "Neither = none of the two, Either = any of two"
        }
    ]
}

{
    "title": "2. No - none (before a noun)",
    "sections": [
        {
            "label": "Primary use",
            "color": "rose",
            "description": "<strong>No</strong> is an adjective that stands <strong>before a noun</strong> and means "none, none".",
            "examples": [
                {
                    "en": "I have no money.",
                    "ua": "I have no money. (no money)"
                },
                {
                    "en": "There are no students in the class.",
                    "ua": "There are no students in the class."
                },
                {
                    "en": "She has no time for this.",
                    "ua": "She has no time for this."
                },
                {
                    "en": "No problem!",
                    "ua": "No problem! (no problem)"
                }
            ]
        },
        {
            "label": "With both types of nouns",
            "color": "amber",
            "description": "<strong>No</strong> works with <strong>countable and uncountable</strong> nouns.",
            "examples": [
                {
                    "en": "no books (countable)",
                    "ua": "no books (countable)"
                },
                {
                    "en": "no water (uncountable)",
                    "ua": "no water (uncountable)"
                },
                {
                    "en": "no friends, no information",
                    "ua": "no friends, no information"
                }
            ]
        },
        {
            "label": "No instead of not any",
            "color": "sky",
            "description": "<strong>No</strong> is a more categorical form objection.",
            "examples": [
                {
                    "en": "I have no money. = I don't have any money.",
                    "ua": "I don't have any money."
                },
                {
                    "en": "There are no tickets. = There aren't any tickets.",
                    "ua": "No tickets."
                }
            ],
            "note": "📌 <strong>No</strong> is more emphatic (categorical)."
        }
    ]
}

{
    "title": "3. None (pronoun)",
    "sections": [
        {
            "label": "Use without a noun",
            "color": "purple",
            "description": "<strong>None</strong> is a pronoun that is <strong>used alone</strong> (without a noun after it).",
            "examples": [
                {
                    "en": "How many do you have? — None.",
                    "ua": "How many do you have? — None."
                },
                {
                    "en": "I wanted some coffee, but there was none.",
                    "ua": "I wanted some coffee, but there was none."
                },
                {
                    "en": "None arrived on time.",
                    "ua": "None came on time."
                }
            ]
        },
        {
            "label": "None of + noun",
            "color": "rose",
            "description": "<strong>None of</strong> + definite noun (the, these, my, etc.).",
            "examples": [
                {
                    "en": "None of the students passed.",
                    "ua": "None of the students passed compiled."
                },
                {
                    "en": "None of my friends came.",
                    "ua": "None of my friends came."
                },
                {
                    "en": "None of this is true.",
                    "ua": "None of this is true."
                },
                {
                    "en": "None of us knows the answer.",
                    "ua": "None of us knows the answers."
                }
            ]
        },
        {
            "label": "Difference: No vs None",
            "color": "sky",
            "description": "The main difference is the position and presence of the noun.",
            "examples": [
                {
                    "en": "No students came. (before a noun)",
                    "ua": "No students came."
                },
                {
                    "en": "None came. (no noun)",
                    "ua": "None of the students came."
                },
                {
                    "en": "None of the students came. (of + noun)",
                    "ua": "None of the students came."
                }
            ],
            "note": "📌 <strong>No</strong> + noun, <strong>None</strong> — independently or with of."
        }
    ]
}

{
    "title": "4. Neither option is good. good.",
    "sections": [
        {
            "label": "Негативний вибір з двох",
            "color": "blue",
            "description": "<strong>Neither</strong> означає «<strong>жоден з двох</strong>» (негативне значення).",
            "examples": [
                {
                    "en": "Neither option is good.",
                    "ua": "Жоден з двох варіантів не хороший."
                },
                {
                    "en": "Neither answer is correct.",
                    "ua": "Neither of the two answers is correct."
                },
                {
                    "en": "Neither team won.",
                    "ua": "Neither of the two teams won."
                }
            ]
        },
        {
            "label": "Neither of + noun",
            "color": "purple",
            "description": "<strong>Neither of</strong> + defined plural noun.",
            "examples": [
                {
                    "en": "Neither of the books is interesting.",
                    "ua": "Neither of them came."
                },
                {
                    "en": "Neither of them came.",
                    "ua": "Neither of them (two) came."
                },
                {
                    "en": "Neither of my parents speaks English.",
                    "ua": "None neither of my parents speak English."
                }
            ]
        },
        {
            "label": "Neither... nor...",
            "color": "rose",
            "description": "The <strong>neither... nor...</strong> construction is "no... no...".",
            "examples": [
                {
                    "en": "Neither John nor Mary came.",
                    "ua": "Neither John nor Mary came."
                },
                {
                    "en": "I like neither tea nor coffee.",
                    "ua": "I don't like tea or coffee."
                },
                {
                    "en": "It's neither hot nor cold.",
                    "ua": "It's neither hot nor cold."
                }
            ],
            "note": "⚠️ <strong>Neither</strong> already contains a negation — not needed!"
        }
    ]
}

{
    "title": "5. Either - any (of two)",
    "sections": [
        {
            "label": "Positive choice of two",
            "color": "emerald",
            "description": "<strong>Either</strong> means "<strong>any of two</strong>" (positive value).",
            "examples": [
                {
                    "en": "Either option is fine.",
                    "ua": "Either of two options "
                },
                {
                    "en": "You can take either book.",
                    "ua": "You can take either book."
                },
                {
                    "en": "Either way works for me.",
                    "ua": "Either of two ways works for me."
                }
            ]
        },
        {
            "label": "Either of + noun",
            "color": "sky",
            "description": "<strong>Either of</strong> + defined plural noun.",
            "examples": [
                {
                    "en": "Either of the books is good.",
                    "ua": "Either of the two books is good."
                },
                {
                    "en": "Either of them can help you.",
                    "ua": "Any of them (two) can help you."
                },
                {
                    "en": "You can choose either of these.",
                    "ua": "You can choose any of these (two)."
                }
            ]
        },
        {
            "label": "Either... or...",
            "color": "amber",
            "description": "The <strong>either... or...</strong> construction is "or... or...".",
            "examples": [
                {
                    "en": "You can have either tea or coffee.",
                    "ua": "You can take either tea or coffee."
                },
                {
                    "en": "Either John or Mary will come.",
                    "ua": "Either John or Mary will come."
                },
                {
                    "en": "It's either right or wrong.",
                    "ua": "It's either right or wrong."
                }
            ]
        }
    ]
}

{
    "title": "6. Neither vs Either - difference",
    "sections": [
        {
            "label": "Negative vs Positive",
            "color": "purple",
            "description": "<strong>Neither</strong> = neither (negative), <strong>Either</strong> = either (positive).",
            "examples": [
                {
                    "en": "Neither book is good. ❌ (neither is good)",
                    "ua": "Either book is good."
                },
                {
                    "en": "Either book is good. ✓ (either is good)",
                    "ua": "Either of the two books is good."
                }
            ]
        },
        {
            "label": "In negations",
            "color": "rose",
            "description": "<strong>Either</strong> can also be used in <strong>negations</strong> = "neither".",
            "examples": [
                {
                    "en": "I don't like coffee. — I don't like it either.",
                    "ua": "I don't like coffee. — I don't love her either. "
                },
                {
                    "en": "She can't come. — He can't come either.",
                    "ua": "She can't come. - He can't either."
                }
            ],
            "note": "📌 In negatives <strong>either</strong> = "too (not)", and <strong>neither</strong> = "also not" (without not)."
        },
        {
            "label": "Neither vs Either in sentences",
            "color": "sky",
            "description": "Comparison of usage:",
            "examples": [
                {
                    "en": "Neither of them came. (none came)",
                    "ua": "None of them came."
                },
                {
                    "en": "Either of them can come. (anyone can)",
                    "ua": "Any of them can come."
                },
                {
                    "en": "Neither option works. (none works)",
                    "ua": "Either option works."
                },
                {
                    "en": "Either option works. (any one works)",
                    "ua": "Any option works."
                }
            ]
        }
    ]
}

{
    "title": "7. Agreement with the verb",
    "sections": [
        {
            "label": "No + noun",
            "color": "amber",
            "description": "The verb agrees with the <strong>noun</strong> after no.",
            "examples": [
                {
                    "en": "No student is here. (singular)",
                    "ua": "No students are here."
                },
                {
                    "en": "No students are here. (plural)",
                    "ua": "No students are here."
                }
            ]
        },
        {
            "label": "None is singular or plural",
            "color": "sky",
            "description": "<strong>None</strong> can be used with a <strong>singular or plural</strong> verb.",
            "examples": [
                {
                    "en": "None of the students is/are here.",
                    "ua": "None of the students are here."
                },
                {
                    "en": "None was found. (formal)",
                    "ua": "None were found."
                },
                {
                    "en": "None were found. (informal)",
                    "ua": "Nothing found."
                }
            ],
            "note": "📌 In modern English, both options are acceptable."
        },
        {
            "label": "Neither/Either is singular",
            "color": "purple",
            "description": "<strong>Neither</strong> and <strong>either</strong> usually with <strong>singular</strong> verb.",
            "examples": [
                {
                    "en": "Neither of them is here. (formal)",
                    "ua": "None of them is here."
                },
                {
                    "en": "Either of them is fine. (formal)",
                    "ua": "Any one of them will do."
                }
            ],
            "note": "📌 In colloquial speech, you can use the plural: Neither/Either of them are..."
        }
    ]
}

{
    "title": "8. Comparison table",
    "intro": "Основні відмінності між no, none, neither, either:",
    "rows": [
        {
            "en": "No",
            "ua": "Жодний (означник)",
            "note": "Перед іменником: no money, no students"
        },
        {
            "en": "None",
            "ua": "Жоден (займенник)",
            "note": "On its own: none came, none of them"
        },
        {
            "en": "Neither",
            "ua": "None of two (negative)",
            "note": "Neither option, neither of them"
        },
        {
            "en": "Either",
            "ua": "Either of two (positive)",
            "note": "Either option, either of them"
        },
        {
            "en": "Neither... nor...",
            "ua": "No... no...",
            "note": "Neither tea nor coffee (double negative)"
        },
        {
            "en": "Either... or...",
            "ua": "Or... or...",
            "note": "Either tea or coffee (choice)"
        }
    ],
    "warning": "📌 <strong>No</strong> — before a noun, <strong>None</strong> — by itself, <strong>Neither/Either</strong> — from two options!"
}

{
    "title": "9. Typical errors",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "None with a noun without of.",
            "wrong": "None students came.",
            "right": " ✅ <span class="font-mono">None of the students came. / No students came.</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Double negative with neither.",
            "wrong": "Neither of them didn't come.",
            "right": " ✅ <span class="font-mono">Neither of them came. (without didn't!)</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Neither/Either with more than two.",
            "wrong": "Neither of the three options works.",
            "right": " ✅ <span class="font-mono">None of the three options works.</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "No of of.",
            "wrong": "No of the students came.",
            "right": " ✅ <span class="font-mono">None of the students came. / No students came.</span>"
        }
    ]
}

{
    "title": "11. Practice",
    "select_title": "Exercise 1. Choose the correct word",
    "select_intro": "Choose no, none, neither or either for each sentence.",
    "selects": [
        {
            "label": "I have ___ money. (no / none)",
            "prompt": "What word?"
        },
        {
            "label": "How many came? — ___. (No / None)",
            "prompt": "What word?"
        },
        {
            "label": "___ of the two books is good. (Neither / None)",
            "prompt": "What word?"
        },
        {
            "label": "___ option works for me. (Either/None) exam.",
            "prompt": "Яке слово?"
        }
    ],
    "options": [
        "Перший варіант",
        "Другий варіант"
    ],
    "input_title": "Вправа 2. Заповни пропуски",
    "input_intro": "Напиши no, none, neither або either.",
    "inputs": [
        {
            "before": "___ of the students passed the exam.",
            "after": "→"
        },
        {
            "before": "There are ___ apples left.",
            "after": "→"
        },
        {
            "before": "___ of them is here. (of two)",
            "after": "→"
        }
    ],
    "rephrase_title": "Exercise 3. Error correction",
    "rephrase_intro": "Find and correct the error in the sentence.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "None students came.",
            "example_target": "None of the students came. / No students came."
        },
        {
            "original": "1. Neither of them didn't come.",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. I have none money.",
            "placeholder": "Correction"
        }
    ]
}

{
    "title": "Other pages from category Nouns, articles and quantity",
    "items": [
        {
            "label": "No / None / Neither / Either (current)",
            "current": true
        },
        {
            "label": "Quantifiers — Much, Many, A Lot, Few, Little",
            "current": false
        },
        {
            "label": "Partitives — a piece of, a cup of…",
            "current": false
        },
        {
            "label": "Zero Article — Zero article",
            "current": false
        }
    ]
}
